#include <stdio.h>
#include <string.h>
#define MOD 1000000007
#define BASE 100001
int hammingDistance(char *a, char *b, int len) {
    int dist = 0;
    for (int i = 0; i < len; i++) {
        if (a[i] != b[i]) {
            dist++;
        }
    }
    return dist;
}
long long hashValue(int *distances, int len) {
    long long hash = 0;
    for (int i = 0; i < len; i++) {
        hash = (hash * BASE + distances[i]) % MOD;
    }
    return hash;
}
int main() {
    char A[100001];
    int K;
    scanf("%s", A);
    scanf("%d", &K);
    int N = strlen(A);
    for (int i = 0; i < K; i++) {
        char B[100001];
        scanf("%s", B);
        int M = strlen(B);
        int distances[N - M + 1];
        for (int j = 0; j <= N - M; j++) {
            char subStr[M + 1];
            strncpy(subStr, A + j, M);
            subStr[M] = '\0';
            distances[j] = hammingDistance(subStr, B, M);
        }
        printf("%lld\n", hashValue(distances, N - M + 1));
    }
    return 0;
}

