import java.util.Scanner;
public class Main {
    static final int MOD = 1000000007;
    static final int BASE = 100001;
    public static int hammingDistance(String a, String b) {
        int dist = 0;
        for (int i = 0; i < b.length(); i++) {
            if (a.charAt(i) != b.charAt(i)) {
                dist++;
            }
        }
        return dist;
    }
    public static long hashValue(int[] distances) {
        long hash = 0;
        for (int i = 0; i < distances.length; i++) {
            hash = (hash * BASE + distances[i]) % MOD;
        }
        return hash;
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        String A = sc.next();
        int K = sc.nextInt();
        int N = A.length();
        for (int i = 0; i < K; i++) {
            String B = sc.next();
            int M = B.length();
            int[] distances = new int[N - M + 1];
            for (int j = 0; j <= N - M; j++) {
                String subStr = A.substring(j, j + M);
                distances[j] = hammingDistance(subStr, B);
            }
            System.out.println(hashValue(distances));
        }
    }
}

